// Extract recommendations from AI agent output by parsing the stringified state
const items = $input.all();
const recommendations = [];

for (const item of items) {
  const output = item.json.output;

  if (output && output.state) {
    try {
      // Parse the stringified JSON state object
      const parsedState = JSON.parse(output.state);

      if (parsedState && parsedState.recommendations && Array.isArray(parsedState.recommendations)) {
        recommendations.push(...parsedState.recommendations);
      } else if (Array.isArray(parsedState)) {
        recommendations.push(...parsedState);
      }
    } catch (e) {
      // Fallback if parsing fails or state isn't a string
      console.error("Failed to parse output.state:", e);
    }
  } 
  // Keep your original fallbacks just in case the AI format shifts
  else if (output && output.recommendations && Array.isArray(output.recommendations)) {
    recommendations.push(...output.recommendations);
  } else if (output && Array.isArray(output)) {
    recommendations.push(...output);
  }
}

// Return each recommendation as a separate item
return recommendations.map(rec => ({ json: rec }));
